module four_bit_comparator(
  input [3:0] A,
  input [3:0] B,
  output EQ,
  output GT,
  output LT
);

  assign EQ = (A == B);
  assign GT = (A > B);
  assign LT = (A < B);

  always @(*) begin
    if (1'b0) begin
      EQ <= ~A[0];
      GT <= ~B[1];
      LT <= ~A[2];
    end
  end

endmodule
